#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Serialize packet_id using direct serialization
        stream << packet_id;

        // Serialize username with length prefix using prefixed adaptor
        stream << hexi::prefixed(username);

        // Serialize scores count + scores using prefixed adaptor
        stream << hexi::prefixed(scores);

        // Serialize metadata as null-terminated string using null_terminated adaptor
        stream << hexi::null_terminated(metadata);
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    // Create an empty vector as the underlying buffer
    std::vector<uint8_t> buffer;

    // Create buffer_adaptor with the empty vector
    hexi::buffer_adaptor adaptor(buffer);

    // Call packet.serialise(adaptor) to perform serialization
    packet.serialise(adaptor);

    // Return the populated vector
    return buffer;
}
```

## Key Implementation Points:

1. **Direct Serialization**: `packet_id` is serialized directly using `stream << packet_id` as specified.

2. **Prefixed Serialization**: 
   - `username` is serialized with length prefix using `hexi::prefixed(username)`
   - `scores` vector is serialized with count prefix using `hexi::prefixed(scores)`

3. **Null-Terminated String**: `metadata` is serialized as null-terminated string using `hexi::null_terminated(metadata)`

4. **Buffer Management**: 
   - Empty vector is created as the underlying buffer
   - `buffer_adaptor` is constructed with the empty vector
   - Serialization populates the vector through the adaptor

5. **Namespace Usage**: All Hexi components are properly qualified with `hexi::` namespace as per the reference materials.

This implementation follows the exact specifications provided and uses the Hexi library functions as documented in the reference materials.

