#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from input buffer
    hexi::buffer_adaptor adaptor(buffer);

    NetworkPacket packet;

    // Read packet_id using read function
    adaptor.read(&packet.packet_id);

    // Read username using prefixed<std::string> adaptor
    adaptor >> hexi::prefixed(packet.username);

    // Read scores vector: first read count, then use read_container
    uint32_t score_count;
    adaptor.read(&score_count);
    hexi::read_container(adaptor, packet.scores, score_count);

    // Read metadata string as null_terminated<std::string>
    adaptor >> hexi::null_terminated(packet.metadata);

    // Skip any remaining padding bytes
    adaptor.skip(adaptor.size());

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from input buffer
